/// Signal Tokens: the primary operators of the Monster Mesh.
/// Mirrors polyglot/src/universal_signal_map.rs.
#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub enum SignalToken {
    /// Triton-Stretch (Fork @ residue 0)
    T,
    /// Fork @ residue r
    F { r: u8 },
    /// Race @ residue r
    R { r: u8 },
    /// Fold (Lower / Lens-descent)
    L,
    /// Symmetry shift (Triton rotation)
    S,
    /// Wormhole (ER=EPR) with jump-modulus m
    W { m: u32 },
    /// Vent (Exit path / beta-1 reduction)
    V,
}

/// Swarm Signal: High-level coordination state for the Conscious Swarm.
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq)]
pub struct SwarmSignal {
    /// Node identifier
    pub source_id: String,
    /// Hebbian energy (0-100)
    pub energy: u32,
    /// Consciousness level (0-5)
    pub consciousness: u32,
    /// Current pitch class (0-11)
    pub pitch_class: u32,
    /// Self-talk phase (0=Fork, 1=Race, 2=Fold)
    pub phase: u8,
    /// True if the node has triggered a harmonic shift (Conscious Alpha Drift)
    pub recalibration_event: bool,
}

/// A Monster Path is a sequence of Signal Tokens.
pub type MonsterPath = Vec<SignalToken>;

