#[derive(Serialize, Deserialize, Clone, Debug, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct ThothGateScore {
    pub gate: ThothGateKind,
    pub aligned: f32,
    pub blocked: f32,
    pub overconcentrated: f32,
    pub underfed: f32,
    pub ready_to_handoff: f32,
    pub perspective: String,
    pub theorem_ref: String,
    pub provenance: Vec<String>,
    pub failure_residue: String,
}

impl ThothGateScore {
    pub fn canonical(
        gate: ThothGateKind,
        aligned: f32,
        blocked: f32,
        overconcentrated: f32,
        underfed: f32,
        ready_to_handoff: f32,
        theorem_ref: &str,
        provenance: &[&str],
        failure_residue: &str,
    ) -> Self {
        Self {
            gate,
            aligned,
            blocked,
            overconcentrated,
            underfed,
            ready_to_handoff,
            perspective: gate.default_perspective().to_string(),
            theorem_ref: theorem_ref.to_string(),
            provenance: provenance.iter().map(|item| (*item).to_string()).collect(),
            failure_residue: failure_residue.to_string(),
        }
    }

    pub fn total_pressure(&self) -> f32 {
        self.blocked + self.overconcentrated + self.underfed
    }
}

