#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub enum ConversationLoopExit {
    StayInDodgeball,
    Walkback,
    Walkaway,
    ArguedClosure,
}

impl ConversationLoopExit {
    pub fn as_attr(self) -> &'static str {
        match self {
            Self::StayInDodgeball => "stayInDodgeball",
            Self::Walkback => "walkback",
            Self::Walkaway => "walkaway",
            Self::ArguedClosure => "arguedClosure",
        }
    }

    pub fn conversation_ended(self) -> bool {
        self == Self::Walkaway
    }
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub enum ConversationClosureKind {
    None,
    Open,
    Closed,
    BoundaryRejected,
    InvalidSilence,
    InvalidBareTruth,
    LieRejected,
    Unresolved,
}

impl ConversationClosureKind {
    pub fn as_attr(self) -> &'static str {
        match self {
            Self::None => "none",
            Self::Open => "open",
            Self::Closed => "closed",
            Self::BoundaryRejected => "boundaryRejected",
            Self::InvalidSilence => "invalidSilence",
            Self::InvalidBareTruth => "invalidBareTruth",
            Self::LieRejected => "lieRejected",
            Self::Unresolved => "unresolved",
        }
    }

    pub fn fact_topology_closed(self) -> bool {
        matches!(self, Self::Closed | Self::BoundaryRejected)
    }
}

