#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
pub struct ThothConversationFrameMetrics {
    pub closure_state: ConversationClosureKind,
    pub loop_exit: ConversationLoopExit,
    pub thoth_move: ThothSemioticMove,
    pub closure_discharge_ids: Vec<String>,
    pub closure_argument_obligation_ids: Vec<String>,
    pub closure_discharge_theorem_ref: String,
    pub open_question_count: u32,
    pub argument_obligation_count: u32,
    pub affect_stall: AffectStallTelemetry,
    pub anti_queue: ConversationAntiQueueTelemetry,
}

impl ThothConversationFrameMetrics {
    pub fn conversation_ended(&self) -> bool {
        self.loop_exit.conversation_ended()
    }

    pub fn keeps_obligation_open(&self) -> bool {
        self.open_question_count > 0
            && !self.conversation_ended()
            && !self.closure_state.fact_topology_closed()
    }

    pub fn keeps_self_antiqueue_open(&self) -> bool {
        self.anti_queue.item_count > 0
    }

    pub fn antiqueue_self_accountability_sound(&self) -> bool {
        self.anti_queue.self_accountability_sound()
    }
}

