    #[cfg(not(target_arch = "wasm32"))]
    #[test]
    fn decode_png_to_grayscale_round_trip() {
        use image::{DynamicImage, ImageBuffer, Luma};
        let img: ImageBuffer<Luma<u8>, Vec<u8>> =
            ImageBuffer::from_fn(12, 8, |x, y| Luma([(x.wrapping_add(y) * 13) as u8]));
        let mut png = Vec::new();
        {
            let mut c = std::io::Cursor::new(&mut png);
            DynamicImage::ImageLuma8(img.clone())
                .write_to(&mut c, image::ImageFormat::Png)
                .unwrap();
        }
        let (row, w, h) = super::decode_png_to_grayscale_row_major(&png).unwrap();
        assert_eq!((w, h), (12, 8));
        assert_eq!(row.len(), 12 * 8);
        assert_eq!(row[0], 0u8);
    }
